-- 50M rows in orders. There IS an index:
-- CREATE INDEX idx_orders_email ON orders (customer_email);
-- ...but the query plan shows a sequential scan, taking 30 seconds.
EXPLAIN ANALYZE
SELECT * FROM orders WHERE customer_email = 'ada@example.com';

options.patchCode:
SET enable_seqscan = off;
EXPLAIN ANALYZE
SELECT * FROM orders WHERE customer_email = 'ada@example.com';
SET enable_seqscan = on;

DROP INDEX idx_orders_email;
CREATE INDEX idx_orders_email ON orders (customer_email);
ANALYZE orders;

EXPLAIN ANALYZE
SELECT * FROM orders WHERE customer_email = 'ada@example.com';
